import{_ as a,o as n,c as o,a2 as e}from"./chunks/framework.B72_uj9U.js";const u=JSON.parse('{"title":"Cargo Install","description":"Publish your agent to crates.io and optimize the cargo install experience for users who build from source.","frontmatter":{"title":"Cargo Install","description":"Publish your agent to crates.io and optimize the cargo install experience for users who build from source."},"headers":[],"relativePath":"learn/linear/17-packaging-and-distribution/04-cargo-install.md","filePath":"learn/linear/17-packaging-and-distribution/04-cargo-install.md"}'),l={name:"learn/linear/17-packaging-and-distribution/04-cargo-install.md"};function t(p,s,c,r,i,y){return n(),o("div",null,[...s[0]||(s[0]=[e(`<h1 id="cargo-install" tabindex="-1">Cargo Install <a class="header-anchor" href="#cargo-install" aria-label="Permalink to &quot;Cargo Install&quot;">​</a></h1><blockquote><p><strong>What you&#39;ll learn:</strong></p><ul><li>How to prepare your crate for publication on crates.io, including metadata, documentation, feature flags, and license configuration</li><li>Techniques for optimizing the cargo install build time by minimizing compile-time dependencies and using feature gates for optional components</li><li>How to handle the challenges of cargo install for end users, including build failures from missing system dependencies and long compile times</li></ul></blockquote><p><code>cargo install</code> is Rust&#39;s equivalent of <code>pip install</code> for command-line tools. It downloads the source from crates.io, compiles it on the user&#39;s machine, and places the binary in <code>~/.cargo/bin/</code>. For Rust developers, this is the most natural installation method. Even for non-Rust developers, it provides a fallback when prebuilt binaries are not available for their platform. This subchapter covers how to prepare your crate for publication and make the <code>cargo install</code> experience as smooth as possible.</p><h2 id="preparing-your-crate-for-publication" tabindex="-1">Preparing Your Crate for Publication <a class="header-anchor" href="#preparing-your-crate-for-publication" aria-label="Permalink to &quot;Preparing Your Crate for Publication&quot;">​</a></h2><p>Before publishing, your <code>Cargo.toml</code> needs complete metadata. Crates.io requires certain fields and uses others for the package listing page:</p><div class="language-toml"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#9399B2;">[</span><span style="color:#CDD6F4;">package</span><span style="color:#9399B2;">]</span></span>
<span class="line"><span style="color:#CDD6F4;">name </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;my-agent&quot;</span></span>
<span class="line"><span style="color:#CDD6F4;">version </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;0.5.2&quot;</span></span>
<span class="line"><span style="color:#CDD6F4;">edition </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;2024&quot;</span></span>
<span class="line"><span style="color:#CDD6F4;">authors </span><span style="color:#94E2D5;">=</span><span style="color:#9399B2;"> [</span><span style="color:#A6E3A1;">&quot;Your Name &lt;you@example.com&gt;&quot;</span><span style="color:#9399B2;">]</span></span>
<span class="line"><span style="color:#CDD6F4;">description </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;A CLI coding agent powered by large language models&quot;</span></span>
<span class="line"><span style="color:#CDD6F4;">readme </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;README.md&quot;</span></span>
<span class="line"><span style="color:#CDD6F4;">license </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;MIT&quot;</span></span>
<span class="line"><span style="color:#CDD6F4;">repository </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;https://github.com/yourname/my-agent&quot;</span></span>
<span class="line"><span style="color:#CDD6F4;">homepage </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;https://github.com/yourname/my-agent&quot;</span></span>
<span class="line"><span style="color:#CDD6F4;">keywords </span><span style="color:#94E2D5;">=</span><span style="color:#9399B2;"> [</span><span style="color:#A6E3A1;">&quot;cli&quot;</span><span style="color:#9399B2;">,</span><span style="color:#A6E3A1;"> &quot;agent&quot;</span><span style="color:#9399B2;">,</span><span style="color:#A6E3A1;"> &quot;llm&quot;</span><span style="color:#9399B2;">,</span><span style="color:#A6E3A1;"> &quot;coding&quot;</span><span style="color:#9399B2;">,</span><span style="color:#A6E3A1;"> &quot;ai&quot;</span><span style="color:#9399B2;">]</span></span>
<span class="line"><span style="color:#CDD6F4;">categories </span><span style="color:#94E2D5;">=</span><span style="color:#9399B2;"> [</span><span style="color:#A6E3A1;">&quot;command-line-utilities&quot;</span><span style="color:#9399B2;">,</span><span style="color:#A6E3A1;"> &quot;development-tools&quot;</span><span style="color:#9399B2;">]</span></span>
<span class="line"><span style="color:#CDD6F4;">exclude </span><span style="color:#94E2D5;">=</span><span style="color:#9399B2;"> [</span></span>
<span class="line"><span style="color:#A6E3A1;">    &quot;tests/fixtures/*&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#A6E3A1;">    &quot;docs/*&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#A6E3A1;">    &quot;.github/*&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#A6E3A1;">    &quot;target/*&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">]</span></span></code></pre></div><p>Let&#39;s walk through the important fields:</p><ul><li><strong><code>name</code></strong> -- Must be unique on crates.io. Check availability at <a href="https://crates.io/" target="_blank" rel="noreferrer">crates.io</a> before settling on a name.</li><li><strong><code>version</code></strong> -- Follow <a href="https://semver.org/" target="_blank" rel="noreferrer">Semantic Versioning</a>. Crates.io rejects re-uploads of the same version, so every publish needs a version bump.</li><li><strong><code>license</code></strong> -- Use an <a href="https://spdx.org/licenses/" target="_blank" rel="noreferrer">SPDX identifier</a>. <code>MIT</code>, <code>Apache-2.0</code>, or <code>MIT OR Apache-2.0</code> are the most common for Rust projects.</li><li><strong><code>description</code></strong> -- One sentence. This appears in search results on crates.io.</li><li><strong><code>keywords</code></strong> -- Up to 5. Help users find your crate through search.</li><li><strong><code>categories</code></strong> -- Choose from the <a href="https://crates.io/categories" target="_blank" rel="noreferrer">official list</a>. <code>command-line-utilities</code> is the right fit for CLI agents.</li><li><strong><code>exclude</code></strong> -- Keeps test fixtures, docs, and CI configuration out of the published crate. This reduces download size for <code>cargo install</code> users.</li></ul><div class="custom-block python"><p class="custom-block-title">Coming from Python</p><p>This is similar to <code>pyproject.toml</code> metadata for PyPI publication, where you set <code>name</code>, <code>version</code>, <code>description</code>, <code>license</code>, and classifiers. The key difference: <code>cargo install</code> downloads source and compiles it, while <code>pip install</code> downloads precompiled wheels (or source distributions that may need compilation). There is no equivalent of Python&#39;s <code>wheel</code> format in Rust -- <code>cargo install</code> always builds from source.</p></div><h2 id="feature-flags-for-optional-components" tabindex="-1">Feature Flags for Optional Components <a class="header-anchor" href="#feature-flags-for-optional-components" aria-label="Permalink to &quot;Feature Flags for Optional Components&quot;">​</a></h2><p>Feature flags let users opt into optional functionality. This is critical for <code>cargo install</code> because every dependency adds to the compile time. Users who do not need certain features should not pay the build cost:</p><div class="language-toml"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#9399B2;">[</span><span style="color:#CDD6F4;">features</span><span style="color:#9399B2;">]</span></span>
<span class="line"><span style="color:#CDD6F4;">default </span><span style="color:#94E2D5;">=</span><span style="color:#9399B2;"> [</span><span style="color:#A6E3A1;">&quot;git&quot;</span><span style="color:#9399B2;">,</span><span style="color:#A6E3A1;"> &quot;syntax-highlighting&quot;</span><span style="color:#9399B2;">]</span></span>
<span class="line"><span style="color:#CDD6F4;">git </span><span style="color:#94E2D5;">=</span><span style="color:#9399B2;"> [</span><span style="color:#A6E3A1;">&quot;dep:git2&quot;</span><span style="color:#9399B2;">]</span></span>
<span class="line"><span style="color:#CDD6F4;">syntax-highlighting </span><span style="color:#94E2D5;">=</span><span style="color:#9399B2;"> [</span><span style="color:#A6E3A1;">&quot;dep:syntect&quot;</span><span style="color:#9399B2;">]</span></span>
<span class="line"><span style="color:#CDD6F4;">telemetry </span><span style="color:#94E2D5;">=</span><span style="color:#9399B2;"> [</span><span style="color:#A6E3A1;">&quot;dep:opentelemetry&quot;</span><span style="color:#9399B2;">,</span><span style="color:#A6E3A1;"> &quot;dep:opentelemetry-otlp&quot;</span><span style="color:#9399B2;">]</span></span>
<span class="line"><span style="color:#CDD6F4;">self-update </span><span style="color:#94E2D5;">=</span><span style="color:#9399B2;"> [</span><span style="color:#A6E3A1;">&quot;dep:self_update&quot;</span><span style="color:#9399B2;">]</span></span>
<span class="line"></span>
<span class="line"><span style="color:#9399B2;">[</span><span style="color:#CDD6F4;">dependencies</span><span style="color:#9399B2;">]</span></span>
<span class="line"><span style="color:#CDD6F4;">git2 </span><span style="color:#94E2D5;">=</span><span style="color:#9399B2;"> {</span><span style="color:#CDD6F4;"> version </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;0.19&quot;</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> features </span><span style="color:#94E2D5;">=</span><span style="color:#9399B2;"> [</span><span style="color:#A6E3A1;">&quot;vendored&quot;</span><span style="color:#9399B2;">],</span><span style="color:#CDD6F4;"> optional </span><span style="color:#94E2D5;">=</span><span style="color:#FAB387;"> true</span><span style="color:#9399B2;"> }</span></span>
<span class="line"><span style="color:#CDD6F4;">syntect </span><span style="color:#94E2D5;">=</span><span style="color:#9399B2;"> {</span><span style="color:#CDD6F4;"> version </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;5&quot;</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> optional </span><span style="color:#94E2D5;">=</span><span style="color:#FAB387;"> true</span><span style="color:#9399B2;"> }</span></span>
<span class="line"><span style="color:#CDD6F4;">opentelemetry </span><span style="color:#94E2D5;">=</span><span style="color:#9399B2;"> {</span><span style="color:#CDD6F4;"> version </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;0.27&quot;</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> optional </span><span style="color:#94E2D5;">=</span><span style="color:#FAB387;"> true</span><span style="color:#9399B2;"> }</span></span>
<span class="line"><span style="color:#CDD6F4;">opentelemetry-otlp </span><span style="color:#94E2D5;">=</span><span style="color:#9399B2;"> {</span><span style="color:#CDD6F4;"> version </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;0.27&quot;</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> optional </span><span style="color:#94E2D5;">=</span><span style="color:#FAB387;"> true</span><span style="color:#9399B2;"> }</span></span>
<span class="line"><span style="color:#CDD6F4;">self_update </span><span style="color:#94E2D5;">=</span><span style="color:#9399B2;"> {</span><span style="color:#CDD6F4;"> version </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;0.42&quot;</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> optional </span><span style="color:#94E2D5;">=</span><span style="color:#FAB387;"> true</span><span style="color:#9399B2;"> }</span></span></code></pre></div><p>Users can then install with exactly the features they want:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># Install with default features</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">cargo</span><span style="color:#A6E3A1;"> install</span><span style="color:#A6E3A1;"> my-agent</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Install with all features</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">cargo</span><span style="color:#A6E3A1;"> install</span><span style="color:#A6E3A1;"> my-agent</span><span style="color:#A6E3A1;"> --all-features</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Install with minimal features (fastest build)</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">cargo</span><span style="color:#A6E3A1;"> install</span><span style="color:#A6E3A1;"> my-agent</span><span style="color:#A6E3A1;"> --no-default-features</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Install with specific features</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">cargo</span><span style="color:#A6E3A1;"> install</span><span style="color:#A6E3A1;"> my-agent</span><span style="color:#A6E3A1;"> --no-default-features</span><span style="color:#A6E3A1;"> --features</span><span style="color:#A6E3A1;"> &quot;git,telemetry&quot;</span></span></code></pre></div><p>Design your features so that the <code>default</code> set covers what most users need while keeping build times reasonable. Heavy optional dependencies like <code>syntect</code> (which bundles grammar files and is slow to compile) should be behind a feature flag.</p><h2 id="optimizing-build-time" tabindex="-1">Optimizing Build Time <a class="header-anchor" href="#optimizing-build-time" aria-label="Permalink to &quot;Optimizing Build Time&quot;">​</a></h2><p><code>cargo install</code> compiles your crate from source on the user&#39;s machine. A clean build of a typical coding agent with its dependency tree can take 3-10 minutes depending on the machine. Here are techniques to reduce that:</p><h3 id="minimize-the-dependency-tree" tabindex="-1">Minimize the Dependency Tree <a class="header-anchor" href="#minimize-the-dependency-tree" aria-label="Permalink to &quot;Minimize the Dependency Tree&quot;">​</a></h3><p>Every dependency you add extends the <code>cargo install</code> time. Audit your dependencies regularly:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># Count your dependencies (including transitive)</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">cargo</span><span style="color:#A6E3A1;"> tree</span><span style="color:#94E2D5;"> |</span><span style="color:#89B4FA;font-style:italic;"> wc</span><span style="color:#A6E3A1;"> -l</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Visualize the dependency tree</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">cargo</span><span style="color:#A6E3A1;"> tree</span><span style="color:#A6E3A1;"> --depth</span><span style="color:#FAB387;"> 2</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Find duplicate versions of the same crate</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">cargo</span><span style="color:#A6E3A1;"> tree</span><span style="color:#A6E3A1;"> --duplicates</span></span></code></pre></div><p>Look for opportunities to replace heavy dependencies with lighter alternatives:</p><table tabindex="0"><thead><tr><th>Heavy Dependency</th><th>Lighter Alternative</th><th>Savings</th></tr></thead><tbody><tr><td><code>chrono</code></td><td><code>time</code> or <code>jiff</code></td><td>~20 crates removed</td></tr><tr><td><code>clap</code> (derive)</td><td><code>clap</code> (builder) or <code>lexopt</code></td><td>Faster proc-macro compile</td></tr><tr><td><code>regex</code></td><td><code>memchr</code> (for simple patterns)</td><td>~5 crates removed</td></tr><tr><td><code>serde_json</code> (for simple cases)</td><td><code>simd-json</code> or manual parsing</td><td>Marginal</td></tr></tbody></table><h3 id="use-workspace-hack-crates-for-development" tabindex="-1">Use Workspace Hack Crates (for Development) <a class="header-anchor" href="#use-workspace-hack-crates-for-development" aria-label="Permalink to &quot;Use Workspace Hack Crates (for Development)&quot;">​</a></h3><p>If your agent is in a workspace with multiple crates, a &quot;workspace hack&quot; crate unifies feature flags across workspace members to avoid recompilation. The <code>cargo-hakari</code> tool automates this:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#89B4FA;font-style:italic;">cargo</span><span style="color:#A6E3A1;"> install</span><span style="color:#A6E3A1;"> cargo-hakari</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">cargo</span><span style="color:#A6E3A1;"> hakari</span><span style="color:#A6E3A1;"> generate</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">cargo</span><span style="color:#A6E3A1;"> hakari</span><span style="color:#A6E3A1;"> manage-deps</span></span></code></pre></div><p>This is primarily a development-time optimization rather than a <code>cargo install</code> optimization, but it matters if your published crate is part of a workspace.</p><h3 id="conditional-compilation-for-expensive-features" tabindex="-1">Conditional Compilation for Expensive Features <a class="header-anchor" href="#conditional-compilation-for-expensive-features" aria-label="Permalink to &quot;Conditional Compilation for Expensive Features&quot;">​</a></h3><p>Gate expensive compile-time operations behind feature flags:</p><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#F9E2AF;font-style:italic;">#</span><span style="color:#9399B2;">[</span><span style="color:#F9E2AF;font-style:italic;">cfg</span><span style="color:#9399B2;">(</span><span style="color:#F9E2AF;font-style:italic;">feature </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;syntax-highlighting&quot;</span><span style="color:#9399B2;">)]</span></span>
<span class="line"><span style="color:#CBA6F7;">mod</span><span style="color:#FAB387;"> syntax</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CBA6F7;">    use</span><span style="color:#F9E2AF;"> syntect</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;">easy</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;font-style:italic;">HighlightLines</span><span style="color:#9399B2;">;</span></span>
<span class="line"><span style="color:#CBA6F7;">    use</span><span style="color:#F9E2AF;"> syntect</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;">parsing</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;font-style:italic;">SyntaxSet</span><span style="color:#9399B2;">;</span></span>
<span class="line"><span style="color:#CBA6F7;">    use</span><span style="color:#F9E2AF;"> syntect</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;">highlighting</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;font-style:italic;">ThemeSet</span><span style="color:#9399B2;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CBA6F7;">    pub</span><span style="color:#CBA6F7;"> fn</span><span style="color:#89B4FA;font-style:italic;"> highlight_code</span><span style="color:#9399B2;">(</span><span style="color:#EBA0AC;">code</span><span style="color:#94E2D5;">:</span><span style="color:#94E2D5;"> &amp;</span><span style="color:#F9E2AF;font-style:italic;">str</span><span style="color:#9399B2;">,</span><span style="color:#EBA0AC;"> language</span><span style="color:#94E2D5;">:</span><span style="color:#94E2D5;"> &amp;</span><span style="color:#F9E2AF;font-style:italic;">str</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;"> -&gt;</span><span style="color:#F9E2AF;font-style:italic;"> String</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CBA6F7;">        let</span><span style="color:#CDD6F4;"> ss </span><span style="color:#94E2D5;">=</span><span style="color:#F9E2AF;font-style:italic;"> SyntaxSet</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">load_defaults_newlines</span><span style="color:#9399B2;">();</span></span>
<span class="line"><span style="color:#CBA6F7;">        let</span><span style="color:#CDD6F4;"> ts </span><span style="color:#94E2D5;">=</span><span style="color:#F9E2AF;font-style:italic;"> ThemeSet</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">load_defaults</span><span style="color:#9399B2;">();</span></span>
<span class="line"><span style="color:#CBA6F7;">        let</span><span style="color:#CDD6F4;"> syntax </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> ss</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">find_syntax_by_token</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">language</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#94E2D5;">            .</span><span style="color:#89B4FA;font-style:italic;">unwrap_or_else</span><span style="color:#9399B2;">(</span><span style="color:#94E2D5;">||</span><span style="color:#CDD6F4;"> ss</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">find_syntax_plain_text</span><span style="color:#9399B2;">());</span></span>
<span class="line"><span style="color:#CBA6F7;">        let</span><span style="color:#CBA6F7;"> mut</span><span style="color:#CDD6F4;"> h </span><span style="color:#94E2D5;">=</span><span style="color:#F9E2AF;font-style:italic;"> HighlightLines</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">new</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">syntax</span><span style="color:#9399B2;">,</span><span style="color:#94E2D5;"> &amp;</span><span style="color:#CDD6F4;">ts</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;">themes</span><span style="color:#9399B2;">[</span><span style="color:#A6E3A1;">&quot;base16-ocean.dark&quot;</span><span style="color:#9399B2;">]);</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">        // ... highlighting logic</span></span>
<span class="line"><span style="color:#CDD6F4;">        code</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">to_string</span><span style="color:#9399B2;">()</span></span>
<span class="line"><span style="color:#9399B2;">    }</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span>
<span class="line"></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">#</span><span style="color:#9399B2;">[</span><span style="color:#F9E2AF;font-style:italic;">cfg</span><span style="color:#9399B2;">(</span><span style="color:#F9E2AF;font-style:italic;">not</span><span style="color:#9399B2;">(</span><span style="color:#F9E2AF;font-style:italic;">feature </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;syntax-highlighting&quot;</span><span style="color:#9399B2;">))]</span></span>
<span class="line"><span style="color:#CBA6F7;">mod</span><span style="color:#FAB387;"> syntax</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CBA6F7;">    pub</span><span style="color:#CBA6F7;"> fn</span><span style="color:#89B4FA;font-style:italic;"> highlight_code</span><span style="color:#9399B2;">(</span><span style="color:#EBA0AC;">code</span><span style="color:#94E2D5;">:</span><span style="color:#94E2D5;"> &amp;</span><span style="color:#F9E2AF;font-style:italic;">str</span><span style="color:#9399B2;">,</span><span style="color:#EBA0AC;"> _language</span><span style="color:#94E2D5;">:</span><span style="color:#94E2D5;"> &amp;</span><span style="color:#F9E2AF;font-style:italic;">str</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;"> -&gt;</span><span style="color:#F9E2AF;font-style:italic;"> String</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CDD6F4;">        code</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">to_string</span><span style="color:#9399B2;">()</span></span>
<span class="line"><span style="color:#9399B2;">    }</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><h2 id="the-publishing-workflow" tabindex="-1">The Publishing Workflow <a class="header-anchor" href="#the-publishing-workflow" aria-label="Permalink to &quot;The Publishing Workflow&quot;">​</a></h2><p>Once your metadata is ready, publish with:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># Dry run -- checks everything without actually publishing</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">cargo</span><span style="color:#A6E3A1;"> publish</span><span style="color:#A6E3A1;"> --dry-run</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Review what will be included in the published crate</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">cargo</span><span style="color:#A6E3A1;"> package</span><span style="color:#A6E3A1;"> --list</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Publish to crates.io (requires authentication)</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">cargo</span><span style="color:#A6E3A1;"> login</span><span style="color:#6C7086;font-style:italic;">  # paste your API token from crates.io/settings/tokens</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">cargo</span><span style="color:#A6E3A1;"> publish</span></span></code></pre></div><p>The <code>--dry-run</code> step is essential. It catches missing files, invalid metadata, and dependency issues before you make an irreversible publish. Remember: you cannot unpublish or overwrite a version on crates.io. You can only <code>yank</code> it (mark it as broken), which prevents new installations but does not remove it from existing lock files.</p><h3 id="versioning-discipline" tabindex="-1">Versioning Discipline <a class="header-anchor" href="#versioning-discipline" aria-label="Permalink to &quot;Versioning Discipline&quot;">​</a></h3><p>Follow a strict versioning workflow:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># Bump version in Cargo.toml (use cargo-edit for convenience)</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">cargo</span><span style="color:#A6E3A1;"> install</span><span style="color:#A6E3A1;"> cargo-edit</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">cargo</span><span style="color:#A6E3A1;"> set-version</span><span style="color:#FAB387;"> 0.5.3</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Or for a specific bump type:</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">cargo</span><span style="color:#A6E3A1;"> set-version</span><span style="color:#A6E3A1;"> --bump</span><span style="color:#A6E3A1;"> patch</span><span style="color:#6C7086;font-style:italic;">  # 0.5.2 -&gt; 0.5.3</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">cargo</span><span style="color:#A6E3A1;"> set-version</span><span style="color:#A6E3A1;"> --bump</span><span style="color:#A6E3A1;"> minor</span><span style="color:#6C7086;font-style:italic;">  # 0.5.2 -&gt; 0.6.0</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">cargo</span><span style="color:#A6E3A1;"> set-version</span><span style="color:#A6E3A1;"> --bump</span><span style="color:#A6E3A1;"> major</span><span style="color:#6C7086;font-style:italic;">  # 0.5.2 -&gt; 1.0.0</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Commit, tag, push, publish</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">git</span><span style="color:#A6E3A1;"> add</span><span style="color:#A6E3A1;"> Cargo.toml</span><span style="color:#A6E3A1;"> Cargo.lock</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">git</span><span style="color:#A6E3A1;"> commit</span><span style="color:#A6E3A1;"> -m</span><span style="color:#A6E3A1;"> &quot;release: v0.5.3&quot;</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">git</span><span style="color:#A6E3A1;"> tag</span><span style="color:#A6E3A1;"> v0.5.3</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">git</span><span style="color:#A6E3A1;"> push</span><span style="color:#9399B2;"> &amp;&amp;</span><span style="color:#89B4FA;font-style:italic;"> git</span><span style="color:#A6E3A1;"> push</span><span style="color:#A6E3A1;"> --tags</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">cargo</span><span style="color:#A6E3A1;"> publish</span></span></code></pre></div><h2 id="handling-build-failures" tabindex="-1">Handling Build Failures <a class="header-anchor" href="#handling-build-failures" aria-label="Permalink to &quot;Handling Build Failures&quot;">​</a></h2><p>The biggest challenge with <code>cargo install</code> is that it requires the user to have a working Rust toolchain and any C compilation dependencies. Common failure modes:</p><table tabindex="0"><thead><tr><th>Failure</th><th>Cause</th><th>Solution</th></tr></thead><tbody><tr><td>&quot;linker &#39;cc&#39; not found&quot;</td><td>No C compiler installed</td><td>User needs <code>build-essential</code> (Linux) or Xcode (macOS)</td></tr><tr><td>&quot;failed to run custom build command for openssl-sys&quot;</td><td>Missing OpenSSL headers</td><td>Switch to <code>rustls</code> or instruct user to install <code>libssl-dev</code></td></tr><tr><td>&quot;error: could not compile...&quot;</td><td>Old Rust version</td><td>Specify <code>rust-version</code> in Cargo.toml</td></tr><tr><td>Timeout / killed</td><td>Insufficient RAM</td><td>Reduce <code>codegen-units</code>, disable LTO for install builds</td></tr></tbody></table><p>Mitigate these proactively:</p><div class="language-toml"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#9399B2;">[</span><span style="color:#CDD6F4;">package</span><span style="color:#9399B2;">]</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Specify minimum Rust version</span></span>
<span class="line"><span style="color:#CDD6F4;">rust-version </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;1.80&quot;</span></span></code></pre></div><p>And in your README, provide clear installation instructions:</p><div class="language-markdown"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#FAB387;">## Installation</span></span>
<span class="line"></span>
<span class="line"><span style="color:#F9E2AF;">### Prebuilt binaries (recommended)</span></span>
<span class="line"><span style="color:#CDD6F4;">Download from </span><span style="color:#B4BEFE;">[</span><span style="color:#B4BEFE;">Releases</span><span style="color:#B4BEFE;">]</span><span style="color:#9399B2;">(</span><span style="color:#89B4FA;">https://github.com/yourname/my-agent/releases</span><span style="color:#9399B2;">)</span></span>
<span class="line"></span>
<span class="line"><span style="color:#F9E2AF;">### From source</span></span>
<span class="line"><span style="color:#CDD6F4;">Requires Rust 1.80+ and a C compiler:</span></span>
<span class="line"><span style="color:#9399B2;">\`\`\`</span><span style="color:#89DCEB;">bash</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">cargo</span><span style="color:#A6E3A1;"> install</span><span style="color:#A6E3A1;"> my-agent</span></span></code></pre></div><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span></span></span>
<span class="line"><span>Always list prebuilt binaries as the primary installation method and \`cargo install\` as the fallback for Rust developers or unsupported platforms.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>::: wild In the Wild</span></span>
<span class="line"><span>Most production coding agents do not rely on \`cargo install\` as their primary distribution method. It requires a Rust toolchain (which most users do not have), takes several minutes to compile, and can fail if system dependencies are missing. Production agents like Claude Code and similar tools distribute prebuilt binaries through Homebrew, GitHub Releases, or platform-specific package managers. However, \`cargo install\` remains valuable as a fallback and is the standard method for the Rust developer community.</span></span>
<span class="line"><span>:::</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## Key Takeaways</span></span>
<span class="line"><span></span></span>
<span class="line"><span>- Complete your \`Cargo.toml\` metadata (description, license, repository, keywords, categories) before publishing to crates.io.</span></span>
<span class="line"><span>- Use feature flags to gate optional, heavy dependencies so users can minimize compile time with \`--no-default-features\`.</span></span>
<span class="line"><span>- Always run \`cargo publish --dry-run\` before a real publish -- crates.io versions are immutable once published.</span></span>
<span class="line"><span>- Specify \`rust-version\` in your package metadata so users with older toolchains get a clear error instead of a confusing compilation failure.</span></span>
<span class="line"><span>- Position \`cargo install\` as a secondary installation method behind prebuilt binaries -- it requires a Rust toolchain and can be slow.</span></span></code></pre></div>`,44)])])}const h=a(l,[["render",t]]);export{u as __pageData,h as default};
